	test(1, CMPLXL(90.01, 13.37), CMPLXL(0xf.fffffffffffffffp-4L, 0x9.bf7113b8d9222d7p-262L), CMPLXL(0x8.0p-3L, 0x9.bf7113b8d9222d8p-262L), CMPLXL(0x8.000000000000001p-3L, 0x9.bf7113b8d9222d9p-262L), 0);
	test(2, CMPLXL(-12.34, 13.37), CMPLXL(-0x8.000000000c43f1p-3L, 0xa.81e1c6f9a2f1f13p-38L), CMPLXL(-0x8.000000000c43f0fp-3L, 0xa.81e1c6f9a2f1f14p-38L), CMPLXL(-0x8.000000000c43f0ep-3L, 0xa.81e1c6f9a2f1f15p-38L), 0);
	test(3, CMPLXL(nanl(""), 13.37), CMPLXL(nanl(""), nanl("")), CMPLXL(nanl(""), nanl("")), CMPLXL(nanl(""), nanl("")), 0);
