	test(7, CMPLXL(90.01, -12.34), CMPLXL(0xf.fffffffffffffffp-4L, 0x8.88a015c8ad3f8fp-263L), CMPLXL(0x8.0p-3L, 0x8.88a015c8ad3f8f1p-263L), CMPLXL(0x8.000000000000001p-3L, 0x8.88a015c8ad3f8f2p-263L), 0);
