	test(19, CMPLXL(90.01, strtold("inf", NULL)), CMPLXL(nanl(""), nanl("")), CMPLXL(nanl(""), nanl("")), CMPLXL(nanl(""), nanl("")), 0);
	test(20, CMPLXL(-12.34, strtold("inf", NULL)), CMPLXL(nanl(""), nanl("")), CMPLXL(nanl(""), nanl("")), CMPLXL(nanl(""), nanl("")), 0);
	test(21, CMPLXL(nanl(""), strtold("inf", NULL)), CMPLXL(nanl(""), nanl("")), CMPLXL(nanl(""), nanl("")), CMPLXL(nanl(""), nanl("")), 0);
	test(22, CMPLXL(strtold("inf", NULL), strtold("inf", NULL)), CMPLXL(0xf.fffffffffffffffp-4L, -0x0.000000000000001p-16385L), CMPLXL(0x8.0p-3L, 0x0.0p+0L), CMPLXL(0x8.000000000000001p-3L, 0x0.000000000000001p-16385L), 0);
	test(23, CMPLXL(strtold("-inf", NULL), strtold("inf", NULL)), CMPLXL(-0x8.000000000000001p-3L, -0x0.000000000000001p-16385L), CMPLXL(-0x8.0p-3L, 0x0.0p+0L), CMPLXL(-0xf.fffffffffffffffp-4L, 0x0.000000000000001p-16385L), 0);
	test(24, CMPLXL(0.0, strtold("inf", NULL)), CMPLXL(-0x0.000000000000001p-16385L, nanl("")), CMPLXL(0x0.0p+0L, nanl("")), CMPLXL(0x0.000000000000001p-16385L, nanl("")), 0);
